import app from 'flarum/admin/app';
app.initializers.add('resofire/avatars', () => {
  const styles = ['random', 'cyberpunk', 'android', 'orc', 'undead', 'pirate', 'glitch', 'emoji', 'sugar-skull', 'lcd-face', 'cassette', 'eye', 'treant'];
  const styleOptions = {};
  styles.forEach(key => {
    styleOptions[key] = app.translator.trans(`resofire-avatars.admin.style_options.${key}`).toString();
  });
  let flushing = false;
  let flushMessage = '';
  const flush = () => {
    if (flushing) return;
    flushing = true;
    flushMessage = '';
    app.request({
      method: 'POST',
      url: app.forum.attribute('apiUrl') + '/resofire-avatars/flush'
    }).then(data => {
      flushMessage = app.translator.trans('resofire-avatars.admin.flush_success', {
        users: data.flushed,
        files: data.filesDeleted
      }).toString();
    }).catch(() => {
      flushMessage = app.translator.trans('resofire-avatars.admin.flush_error').toString();
    }).finally(() => {
      flushing = false;
      m.redraw();
    });
  };
  app.extensionData.for('resofire-avatars').registerSetting({
    setting: 'resofire-avatars.default_style',
    label: app.translator.trans('resofire-avatars.admin.default_style'),
    help: app.translator.trans('resofire-avatars.admin.default_style_help'),
    type: 'select',
    options: styleOptions
  }).registerSetting(() => m("div", {
    className: "Form-group"
  }, m("label", null, app.translator.trans('resofire-avatars.admin.flush_label')), m("p", {
    className: "helpText"
  }, app.translator.trans('resofire-avatars.admin.flush_help')), m("button", {
    className: "Button Button--danger",
    onclick: flush,
    disabled: flushing
  }, flushing ? app.translator.trans('resofire-avatars.admin.flush_running') : app.translator.trans('resofire-avatars.admin.flush_button')), flushMessage ? m("p", {
    style: {
      marginTop: '8px'
    }
  }, flushMessage) : null));
});